#ifndef RTOS_EVENT_GROUP_H
#define RTOS_EVENT_GROUP_H
#include <Arduino.h>
#include <freertos/FreeRTOS.h>
#include <freertos/event_groups.h>

// Define event bits
#define EVT_WIFI_READY    (1 << 0)
#define EVT_SENSOR_INIT   (1 << 1)
#define EVT_MQTT_CONN     (1 << 2)
#define EVT_BLE_CONN      (1 << 3)
#define EVT_OTA_START     (1 << 4)
#define EVT_ERROR         (1 << 7)

EventGroupHandle_t rtos_event_group_create();
void rtos_event_set(EventGroupHandle_t eg, EventBits_t bits);
void rtos_event_clear(EventGroupHandle_t eg, EventBits_t bits);
EventBits_t rtos_event_wait(EventGroupHandle_t eg, EventBits_t bits, bool waitAll, uint32_t timeoutMs);
EventBits_t rtos_event_get(EventGroupHandle_t eg);

#endif

firmware_template.source:
#include "rtos_event_group.h"

EventGroupHandle_t rtos_event_group_create() {
    EventGroupHandle_t eg = xEventGroupCreate();
    if (eg) Serial.println("[rtos-evt] Event group created");
    return eg;
}

void rtos_event_set(EventGroupHandle_t eg, EventBits_t bits) {
    if (eg) xEventGroupSetBits(eg, bits);
}

void rtos_event_clear(EventGroupHandle_t eg, EventBits_t bits) {
    if (eg) xEventGroupClearBits(eg, bits);
}

EventBits_t rtos_event_wait(EventGroupHandle_t eg, EventBits_t bits, bool waitAll, uint32_t timeoutMs) {
    if (!eg) return 0;
    return xEventGroupWaitBits(eg, bits, pdTRUE, waitAll ? pdTRUE : pdFALSE, pdMS_TO_TICKS(timeoutMs));
}

EventBits_t rtos_event_get(EventGroupHandle_t eg) {
    return eg ? xEventGroupGetBits(eg) : 0;
}
